import{_ as e,o as a,c as n,ai as i}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"消息","description":"","frontmatter":{"read_when":["解释入站消息如何转化为回复","阐明会话、队列模式或流式传输行为","记录推理可见性和使用影响"],"summary":"消息流程、会话、队列和推理可见性","title":"消息","x-i18n":{"generated_at":"2026-02-03T10:05:22Z","model":"claude-opus-4-5","provider":"pi","source_hash":"147362b61bee21ee6e303654d970a052325f076ddb45814306053f70409737b5","source_path":"concepts/messages.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/messages.md","filePath":"zh-CN/concepts/messages.md","lastUpdated":1771906665000}'),l={name:"zh-CN/concepts/messages.md"};function p(o,s,t,d,c,r){return a(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="消息" tabindex="-1"><a class="header-anchor" href="#消息">#</a> 消息</h1><p>本页汇总了 OpenSoul 如何处理入站消息、会话、队列、流式传输和推理可见性。</p><h2 id="消息流程-高层概述" tabindex="-1"><a class="header-anchor" href="#消息流程-高层概述">#</a> 消息流程（高层概述）</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>入站消息</span></span>
<span class="line"><span>  -&gt; 路由/绑定 -&gt; 会话密钥</span></span>
<span class="line"><span>  -&gt; 队列（如果有运行中的任务）</span></span>
<span class="line"><span>  -&gt; 智能体运行（流式传输 + 工具）</span></span>
<span class="line"><span>  -&gt; 出站回复（渠道限制 + 分块）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>关键配置项在配置中：</p><ul><li><code>messages.*</code> 用于前缀、队列和群组行为。</li><li><code>agents.defaults.*</code> 用于分块流式传输和分块默认值。</li><li>渠道覆盖（<code>channels.whatsapp.*</code>、<code>channels.telegram.*</code> 等）用于上限和流式传输开关。</li></ul><p>完整 schema 参见<a href="/docs/gateway/configuration">配置</a>。</p><h2 id="入站去重" tabindex="-1"><a class="header-anchor" href="#入站去重">#</a> 入站去重</h2><p>渠道可能在重新连接后重复投递同一消息。OpenSoul 保持一个短期缓存，以渠道/账户/对端/会话/消息 ID 为键，因此重复投递不会触发另一次智能体运行。</p><h2 id="入站防抖" tabindex="-1"><a class="header-anchor" href="#入站防抖">#</a> 入站防抖</h2><p>来自<strong>同一发送者</strong>的快速连续消息可以通过 <code>messages.inbound</code> 批量合并为单个智能体轮次。防抖按渠道 + 会话为范围，并使用最近的消息进行回复线程/ID 处理。</p><p>配置（全局默认 + 单渠道覆盖）：</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    inbound</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>注意事项：</p><ul><li>防抖仅适用于<strong>纯文本</strong>消息；媒体/附件会立即刷新。</li><li>控制命令会绕过防抖，保持独立。</li></ul><h2 id="会话和设备" tabindex="-1"><a class="header-anchor" href="#会话和设备">#</a> 会话和设备</h2><p>会话由 Gateway 网关拥有，而非客户端。</p><ul><li>直接聊天合并到智能体主会话密钥。</li><li>群组/渠道获得各自的会话密钥。</li><li>会话存储和记录保存在 Gateway 网关主机上。</li></ul><p>多个设备/渠道可以映射到同一会话，但历史记录不会完全同步回每个客户端。建议：对长对话使用一个主设备，以避免上下文分歧。控制 UI 和 TUI 始终显示 Gateway 网关支持的会话记录，因此它们是事实来源。</p><p>详情：<a href="/docs/concepts/session">会话管理</a>。</p><h2 id="入站正文和历史上下文" tabindex="-1"><a class="header-anchor" href="#入站正文和历史上下文">#</a> 入站正文和历史上下文</h2><p>OpenSoul 将<strong>提示正文</strong>与<strong>命令正文</strong>分开：</p><ul><li><code>Body</code>：发送给智能体的提示文本。这可能包括渠道信封和可选的历史包装器。</li><li><code>CommandBody</code>：用于指令/命令解析的原始用户文本。</li><li><code>RawBody</code>：<code>CommandBody</code> 的旧别名（为兼容性保留）。</li></ul><p>当渠道提供历史记录时，使用共享包装器：</p><ul><li><code>[Chat messages since your last reply - for context]</code></li><li><code>[Current message - respond to this]</code></li></ul><p>对于<strong>非直接聊天</strong>（群组/渠道/房间），<strong>当前消息正文</strong>会加上发送者标签前缀（与历史条目使用的样式相同）。这使智能体提示中的实时消息和队列/历史消息保持一致。</p><p>历史缓冲区是<strong>仅待处理的</strong>：它们包含<em>未</em>触发运行的群组消息（例如，提及门控的消息），并<strong>排除</strong>已在会话记录中的消息。</p><p>指令剥离仅适用于<strong>当前消息</strong>部分，因此历史记录保持完整。包装历史记录的渠道应将 <code>CommandBody</code>（或 <code>RawBody</code>）设置为原始消息文本，并将 <code>Body</code> 保留为组合提示。历史缓冲区可通过 <code>messages.groupChat.historyLimit</code>（全局默认）和单渠道覆盖（如 <code>channels.slack.historyLimit</code> 或 <code>channels.telegram.accounts.&lt;id&gt;.historyLimit</code>）进行配置（设置 <code>0</code> 表示禁用）。</p><h2 id="队列和后续消息" tabindex="-1"><a class="header-anchor" href="#队列和后续消息">#</a> 队列和后续消息</h2><p>如果运行已在进行中，入站消息可以排队、导入当前运行，或收集用于后续轮次。</p><ul><li>通过 <code>messages.queue</code>（和 <code>messages.queue.byChannel</code>）配置。</li><li>模式：<code>interrupt</code>、<code>steer</code>、<code>followup</code>、<code>collect</code>，以及积压变体。</li></ul><p>详情：<a href="/docs/concepts/queue">队列</a>。</p><h2 id="流式传输、分块和批处理" tabindex="-1"><a class="header-anchor" href="#流式传输、分块和批处理">#</a> 流式传输、分块和批处理</h2><p>分块流式传输在模型生成文本块时发送部分回复。分块遵循渠道文本限制，避免拆分围栏代码。</p><p>关键设置：</p><ul><li><code>agents.defaults.blockStreamingDefault</code>（<code>on|off</code>，默认 off）</li><li><code>agents.defaults.blockStreamingBreak</code>（<code>text_end|message_end</code>）</li><li><code>agents.defaults.blockStreamingChunk</code>（<code>minChars|maxChars|breakPreference</code>）</li><li><code>agents.defaults.blockStreamingCoalesce</code>（基于空闲的批处理）</li><li><code>agents.defaults.humanDelay</code>（块回复之间的拟人化暂停）</li><li>渠道覆盖：<code>*.blockStreaming</code> 和 <code>*.blockStreamingCoalesce</code>（非 Telegram 渠道需要显式设置 <code>*.blockStreaming: true</code>）</li></ul><p>详情：<a href="/docs/concepts/streaming">流式传输 + 分块</a>。</p><h2 id="推理可见性和-token" tabindex="-1"><a class="header-anchor" href="#推理可见性和-token">#</a> 推理可见性和 token</h2><p>OpenSoul 可以显示或隐藏模型推理：</p><ul><li><code>/reasoning on|off|stream</code> 控制可见性。</li><li>当模型产生推理内容时，它仍计入 token 使用量。</li><li>Telegram 支持将推理流式传输到草稿气泡中。</li></ul><p>详情：<a href="/docs/tools/thinking">思考 + 推理指令</a>和 <a href="/docs/reference/token-use">Token 使用</a>。</p><h2 id="前缀、线程和回复" tabindex="-1"><a class="header-anchor" href="#前缀、线程和回复">#</a> 前缀、线程和回复</h2><p>出站消息格式在 <code>messages</code> 中集中配置：</p><ul><li><code>messages.responsePrefix</code>（出站前缀）和 <code>channels.whatsapp.messagePrefix</code>（WhatsApp 入站前缀）</li><li>通过 <code>replyToMode</code> 和单渠道默认值进行回复线程</li></ul><p>详情：<a href="/docs/gateway/configuration#messages">配置</a>和渠道文档。</p>`,45)])])}const g=e(l,[["render",p]]);export{k as __pageData,g as default};
